    import unicodedata

    if type(x) is not str or len(x) != 24:
        return False

    if any(not (0xFF00 <= ord(c) <= 0xFFEF) for c in x):
        return False

    try:
        y = unicodedata.normalize("NFKC", x).encode("ascii")
    except UnicodeEncodeError:
        return False

    salt = (b"saltSALT" * 4) + b"salt"
    got = hashlib.pbkdf2_hmac("sha1", y, salt, 4096, 25)

    return got[::-1].hex() == (
